Passing OutputStream into this function can avoid create StringBuilder object:
    private void getWorkerPids(Map<Integer, WorkerThread> workerMap, OutputStream os) throws IOException {
        boolean first = true;
        for (Integer pid : workerMap.keySet()) {
            if (pid <= 0) {
                logger.warn("worker pid is not available yet.");
                continue;
            }
            if (first) {
                first = false;
            } else {
                IOUtils.write(",", os,  StandardCharsets.UTF_8);
            }
            IOUtils.write(pid.toString(), os,  StandardCharsets.UTF_8);
        }
    }

